                            <h1 className="text-3xl md:text-5xl font-extrabold text-slate-900 dark:text-white tracking-tight">
                                {t.welcome}
                            </h1>
                            <p className="text-slate-500 dark:text-slate-400 text-lg max-w-2xl mx-auto leading-relaxed">
                                {t.desc}
                            </p>
                        </div>

                        {/* Grouped Tools Grid */}
