export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { IconCopy, IconCheck, IconX, IconSearch, IconJson, IconType, IconPanelLeft } from '../Icons';
import { ToolComponentProps } from '../../types';

// Access global jsonpath object from CDN
declare const jsonpath: any;

// --- Tree View Components ---

const JsonNode = ({ name, value, isLast }: { name?: string, value: any, isLast: boolean }) => {
  const [collapsed, setCollapsed] = useState(false);

  const isObject = value !== null && typeof value === 'object';
  const isArray = Array.isArray(value);
  const isEmpty = isObject && Object.keys(value).length === 0;

  if (!isObject) {
    // Primitive
    const color = typeof value === 'string' ? 'text-green-400' 
                : typeof value === 'number' ? 'text-blue-400' 
                : typeof value === 'boolean' ? 'text-purple-400' 
                : 'text-slate-400'; // null

    return (
      <div className="hover:bg-slate-800/50 px-1 rounded font-mono text-sm leading-6">
        {name && <span className="text-primary-300">"{name}"<span className="text-slate-500">: </span></span>}
        <span className={color}>{JSON.stringify(value)}</span>
        {!isLast && <span className="text-slate-500">,</span>}
      </div>
    );
  }

  // Object / Array
  const keys = Object.keys(value);
  const openBracket = isArray ? '[' : '{';
  const closeBracket = isArray ? ']' : '}';

  if (isEmpty) {
     return (
       <div className="hover:bg-slate-800/50 px-1 rounded font-mono text-sm leading-6">
         {name && <span className="text-primary-300">"{name}"<span className="text-slate-500">: </span></span>}
         <span className="text-slate-500">{openBracket}{closeBracket}</span>
         {!isLast && <span className="text-slate-500">,</span>}
       </div>
     );
  }

  return (
    <div className="group font-mono text-sm leading-6">
       <div className="hover:bg-slate-800/50 px-1 rounded flex items-start">
         <button 
            onClick={(e) => { e.stopPropagation(); setCollapsed(!collapsed); }} 
            className="w-4 h-6 flex items-center justify-center text-slate-500 hover:text-slate-300 mr-1 select-none shrink-0"
         >
            <span className="text-[10px] transform transition-transform duration-200" style={{ transform: collapsed ? 'rotate(-90deg)' : 'rotate(0deg)' }}>▼</span>
         </button>

         <div className="flex-1 min-w-0">
            {name && <span className="text-primary-300">"{name}"<span className="text-slate-500">: </span></span>}
            <span className="text-slate-500">{openBracket}</span>

            {collapsed ? (
                <>
                  <button onClick={() => setCollapsed(false)} className="text-slate-600 text-xs px-2 hover:text-slate-400 select-none bg-slate-800/50 rounded mx-1">...</button>
                  <span className="text-slate-500">{closeBracket}</span>
                  {!isLast && <span className="text-slate-500">,</span>}
                  <span className="text-slate-600 ml-2 text-xs italic">// {isArray ? `${keys.length} items` : `${keys.length} keys`}</span>
                </>
            ) : (
                <>
                   <div className="pl-4 border-l-2 border-slate-800 ml-1.5 my-0.5">
                        {keys.map((key, idx) => (
                            <JsonNode 
                                key={key} 
                                name={isArray ? undefined : key} 
                                value={value[key]} 
                                isLast={idx === keys.length - 1} 
                            />
                        ))}
                    </div>
                    <span className="text-slate-500">{closeBracket}</span>
                    {!isLast && <span className="text-slate-500">,</span>}
                </>
            )}
         </div>
       </div>
    </div>
  );
};

const JsonFormatter: React.FC<ToolComponentProps> = ({ lang }) => {
  const [input, setInput] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [viewMode, setViewMode] = useState<'text' | 'tree'>('text');

  // JSONPath State
  const [showJsonPath, setShowJsonPath] = useState(false);
  const [pathQuery, setPathQuery] = useState('$.');
  const [pathResult, setPathResult] = useState('');
  const [pathError, setPathError] = useState<string | null>(null);

  const t = {
    title: lang === 'zh' ? 'JSON 编辑器' : 'JSON Editor',
    textMode: lang === 'zh' ? '文本' : 'Text',
    treeMode: lang === 'zh' ? '树形' : 'Tree',
    path: lang === 'zh' ? '路径' : 'Path',
    esc: lang === 'zh' ? '转义' : 'Esc',
    unesc: lang === 'zh' ? '去转义' : 'UnEsc',
    format: lang === 'zh' ? '格式化' : 'Format',
    minify: lang === 'zh' ? '压缩' : 'Minify',
    clear: lang === 'zh' ? '清空' : 'Clear',
    sample: lang === 'zh' ? '示例' : 'Sample',
    copy: lang === 'zh' ? '复制' : 'Copy',
    copied: lang === 'zh' ? '已复制' : 'Copied',
    inputTitle: lang === 'zh' ? '输入 JSON' : 'Input JSON',
    treeTitle: lang === 'zh' ? '树形视图' : 'Tree Viewer',
    pathTitle: lang === 'zh' ? 'JSONPath 表达式' : 'JSONPath Expression',
    resultTitle: lang === 'zh' ? '提取结果' : 'Extraction Result',
    readonly: lang === 'zh' ? '只读' : 'ReadOnly',
    invalid: lang === 'zh' ? '无效的 JSON: ' : 'Invalid JSON: ',
    placeholder: lang === 'zh' ? '在此粘贴或输入 JSON...' : 'Paste or type JSON here...',
    empty: lang === 'zh' ? '无效的 JSON - 请切换到文本模式修复错误。' : 'Invalid JSON - switch to Text mode to fix errors.',
    noMatch: lang === 'zh' ? '无匹配' : 'No match',
  };

  // Auto-validate syntax
  useEffect(() => {
    if (!input.trim()) {
      setError(null);
      return;
    }
    try {
      JSON.parse(input);
      setError(null);
    } catch (e: any) {
      setError(e.message);
    }
  }, [input]);

  // Execute JSONPath when input or query changes
  useEffect(() => {
    if (!input.trim() || !pathQuery.trim() || error || typeof jsonpath === 'undefined') {
        setPathResult('');
        return;
    }

    try {
        const jsonData = JSON.parse(input);
        const result = jsonpath.query(jsonData, pathQuery);

        if (result === undefined || result.length === 0) {
            setPathResult(t.noMatch);
            setPathError(null);
        } else {
            setPathResult(JSON.stringify(result, null, 2));
            setPathError(null);
        }
    } catch (e: any) {
        setPathResult('');
    }
  }, [input, pathQuery, error, t.noMatch]);

  const formatJson = () => {
    try {
      const parsed = JSON.parse(input);
      setInput(JSON.stringify(parsed, null, 2));
      setError(null);
      setViewMode('text'); // Formatting usually implies checking the source
    } catch (e: any) {
      setError(t.invalid + e.message);
    }
  };

  const minifyJson = () => {
    try {
      const parsed = JSON.parse(input);
      setInput(JSON.stringify(parsed));
      setError(null);
      setViewMode('text');
    } catch (e: any) {
      setError(t.invalid + e.message);
    }
  };

  const escapeJson = () => {
    try {
        // Escape the string content
        const escaped = JSON.stringify(input);
        setInput(escaped);
        setViewMode('text');
    } catch(e) {
        // Should not happen for string
    }
  };

  const unescapeJson = () => {
      try {
          // Attempt to parse as JSON string
          if (input.startsWith('"') && input.endsWith('"')) {
              const unescaped = JSON.parse(input);
              setInput(unescaped);
          } else {
              // Manual unescape if not wrapped in quotes or parse fails
              const unescaped = input.replace(/\\"/g, '"').replace(/\\\\/g, '\\');
              setInput(unescaped);
          }
          setViewMode('text');
      } catch(e: any) {
          setError(e.message);
      }
  };

  const handleCopy = (text: string) => {
    if (!text) return;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const loadSample = () => {
    const sample = {
        "store": {
            "book": [
                { "category": "reference", "author": "Nigel Rees", "title": "Sayings of the Century", "price": 8.95 },
                { "category": "fiction", "author": "Evelyn Waugh", "title": "Sword of Honour", "price": 12.99 }
            ],
            "bicycle": { "color": "red", "price": 19.95 }
        },
        "expensive": 10
    };
    setInput(JSON.stringify(sample, null, 2));
    setViewMode('tree');
  };

  // Memoize parsed JSON for tree view to avoid re-parsing on every render if input didn't change (though input changes often)
  const parsedJson = useMemo(() => {
      if (!input.trim()) return null;
      try {
          return JSON.parse(input);
      } catch {
          return null;
      }
  }, [input]);

  return (
    <div className="flex flex-col gap-4 h-full min-h-[500px]">
      {/* Toolbar */}
      <div className="flex flex-wrap items-center justify-between gap-3 p-1">
        <div className="flex items-center gap-2">
            <IconJson className="w-5 h-5 text-primary-400" />
            <h2 className="text-lg font-bold text-slate-100">{t.title}</h2>
        </div>
        <div className="flex flex-wrap gap-2 items-center">
            {/* View Mode Toggles */}
            <div className="flex bg-slate-800 rounded-lg p-1 border border-slate-700 mr-2">
                <button
                    onClick={() => setViewMode('text')}
                    className={`px-3 py-1 text-xs font-medium rounded transition-all flex items-center gap-1.5 ${viewMode === 'text' ? 'bg-primary-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
                    title={t.textMode}
                >
                    <IconType className="w-3.5 h-3.5" />
                    {t.textMode}
                </button>
                <button
                    onClick={() => setViewMode('tree')}
                    className={`px-3 py-1 text-xs font-medium rounded transition-all flex items-center gap-1.5 ${viewMode === 'tree' ? 'bg-primary-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
                    title={t.treeMode}
                >
                    <IconPanelLeft className="w-3.5 h-3.5" />
                    {t.treeMode}
                </button>
            </div>

            <button 
                onClick={() => setShowJsonPath(!showJsonPath)} 
                className={`px-3 py-1.5 text-xs font-medium rounded border transition-colors flex items-center gap-2 ${showJsonPath ? 'bg-primary-900/30 border-primary-500/50 text-primary-300' : 'bg-slate-800 border-slate-700 text-slate-300 hover:bg-slate-700'}`}
            >
                <IconSearch className="w-3 h-3" />
                {t.path}
            </button>

            <div className="w-px h-6 bg-slate-700 mx-1 hidden lg:block"></div>

            <div className="flex gap-1">
                 <button onClick={escapeJson} className="px-2 py-1.5 text-xs font-medium bg-slate-800 hover:bg-slate-700 rounded border border-slate-700 text-slate-300 transition-colors" title="Escape JSON string">{t.esc}</button>
                 <button onClick={unescapeJson} className="px-2 py-1.5 text-xs font-medium bg-slate-800 hover:bg-slate-700 rounded border border-slate-700 text-slate-300 transition-colors" title="Unescape JSON string">{t.unesc}</button>
            </div>

            <div className="flex gap-1">
                <button onClick={formatJson} className="px-3 py-1.5 text-xs font-medium bg-primary-600 hover:bg-primary-500 rounded text-white transition-colors">{t.format}</button>
                <button onClick={minifyJson} className="px-3 py-1.5 text-xs font-medium bg-slate-800 hover:bg-slate-700 rounded border border-slate-700 text-slate-300 transition-colors">{t.minify}</button>
            </div>

            <button onClick={() => setInput('')} className="px-3 py-1.5 text-xs font-medium bg-red-900/30 hover:bg-red-900/50 text-red-300 rounded border border-red-900/50 transition-colors">{t.clear}</button>
            <button onClick={loadSample} className="px-3 py-1.5 text-xs font-medium bg-slate-800 hover:bg-slate-700 rounded border border-slate-700 text-slate-300 transition-colors">{t.sample}</button>
        </div>
      </div>

      {/* Main Content: Split View */}
      <div className="flex-1 flex flex-col md:flex-row gap-4 min-h-0">

        {/* Left Column: Input / Tree */}
        <div className="flex-1 flex flex-col gap-2 min-w-0 transition-all duration-300 ease-in-out h-full min-h-[400px]">
            <div className="flex justify-between items-center px-1">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">
                    {viewMode === 'text' ? t.inputTitle : t.treeTitle}
                </span>
                <button onClick={() => handleCopy(input)} className="text-xs flex items-center gap-1 text-slate-500 hover:text-primary-400 transition-colors">
                    {copied ? <IconCheck className="w-3 h-3"/> : <IconCopy className="w-3 h-3"/>} {t.copy}
                </button>
            </div>

            <div className="relative flex-1 group h-full overflow-hidden bg-slate-800 rounded-xl border border-slate-700">
                {viewMode === 'text' ? (
                    <textarea
                        className={`w-full h-full bg-slate-800 text-slate-200 font-mono text-xs sm:text-sm p-4 outline-none resize-none transition-all ${error ? 'focus:ring-2 focus:ring-red-500/50' : 'focus:ring-2 focus:ring-primary-500'}`}
                        placeholder={t.placeholder}
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        spellCheck="false"
                    />
                ) : (
                    <div className="w-full h-full overflow-auto p-4 scrollbar-thin scrollbar-thumb-slate-600">
                        {parsedJson ? (
                            <JsonNode value={parsedJson} isLast={true} />
                        ) : (
                            <div className="text-slate-500 italic text-sm">
                                {input.trim() ? t.empty : (lang === 'zh' ? '空 JSON' : 'Empty JSON')}
                            </div>
                        )}
                    </div>
                )}

                {error && viewMode === 'text' && (
                    <div className="absolute bottom-4 left-4 right-4 bg-red-900/90 text-red-100 px-3 py-2 rounded-lg shadow-lg text-xs flex items-center gap-2 backdrop-blur-sm z-10 animate-in fade-in slide-in-from-bottom-2">
                        <IconX className="w-3 h-3 shrink-0" /> <span className="truncate">{error}</span>
                    </div>
                )}
            </div>
        </div>

        {/* Right Column: JSONPath & Result (Conditional) */}
        {showJsonPath && (
            <div className="flex-1 md:flex-[0.8] lg:flex-1 flex flex-col gap-4 min-w-0 animate-in fade-in slide-in-from-right-4 duration-300 border-l border-slate-700/50 pl-4 md:pl-0 md:border-l-0">
                {/* JSONPath Input Section */}
                <div className="flex flex-col gap-2 shrink-0">
                    <div className="flex items-center gap-2 px-1">
                        <IconSearch className="w-3 h-3 text-slate-400" />
                        <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.pathTitle}</span>
                    </div>
                    <input 
                        type="text" 
                        value={pathQuery}
                        onChange={(e) => setPathQuery(e.target.value)}
                        placeholder="$.store.book[*]"
                        className="w-full bg-slate-900 border border-slate-700 rounded-lg py-2 px-3 text-slate-200 font-mono text-sm focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all placeholder:text-slate-600"
                    />
                </div>

                {/* Result Section */}
                <div className="flex-1 flex flex-col gap-2 min-h-0">
                    <div className="flex justify-between items-center px-1">
                        <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.resultTitle}</span>
                        <span className="text-xs text-slate-600">{t.readonly}</span>
                    </div>
                    <div className="flex-1 relative bg-slate-900 rounded-xl border border-slate-800 overflow-hidden">
                        <textarea 
                            readOnly
                            value={pathResult}
                            className={`absolute inset-0 w-full h-full bg-transparent p-4 font-mono text-xs sm:text-sm resize-none outline-none ${pathResult === t.noMatch ? 'text-slate-500 italic' : 'text-green-400'}`}
                            placeholder={lang === 'zh' ? '结果将显示在这里...' : "Results will appear here..."}
                        />
                    </div>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

export default JsonFormatter;

import React, { useState } from 'react';
import { generateRegex, explainCode } from '../../services/geminiService';
import { GoogleGenAI } from "@google/genai";
import { IconSparkles, IconCopy, IconCheck } from '../Icons';
import { ToolComponentProps } from '../../types';

type Mode = 'regex' | 'explain' | 'convert';

const AiAssistant: React.FC<ToolComponentProps> = ({ lang }) => {
  const [mode, setMode] = useState<Mode>('regex');
  const [input, setInput] = useState('');
  const [output, setOutput] = useState('');
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);

  const t = {
     title: lang === 'zh' ? '智能开发助手' : 'Smart Developer Assistant',
     regex: lang === 'zh' ? '正则生成' : 'Regex Gen',
     explain: lang === 'zh' ? '代码解释' : 'Explain',
     convert: lang === 'zh' ? '代码转换' : 'Convert',
     labelRegex: lang === 'zh' ? '描述匹配规则:' : 'Describe matching rule:',
     labelExplain: lang === 'zh' ? '粘贴代码以解释:' : 'Paste code to explain:',
     labelConvert: lang === 'zh' ? '粘贴代码以转换 (如 Curl):' : 'Paste code to convert (e.g. Curl):',
     phRegex: lang === 'zh' ? '例如：匹配不包含 .org 的有效邮箱地址' : 'e.g., Match valid email addresses excluding .org domains',
     phCode: lang === 'zh' ? '在此粘贴代码...' : 'Paste your code snippet here...',
     gen: lang === 'zh' ? '生成' : 'Generate',
     output: lang === 'zh' ? 'AI 输出' : 'AI Output',
     copy: lang === 'zh' ? '复制' : 'Copy',
     copied: lang === 'zh' ? '已复制' : 'Copied',
     resultPlace: lang === 'zh' ? '结果将显示在这里...' : 'Result will appear here...',
     thinking: lang === 'zh' ? '思考中...' : 'Thinking...',
  };

  const convertCode = async (code: string) => {
    const apiKey = process.env.API_KEY || '';
    if (!apiKey) return "API Key missing";
    const ai = new GoogleGenAI({ apiKey });
    try {
        const prompt = `Convert the following code/request.
        If it looks like a curl command, convert it to Python and JavaScript Fetch.
        If it looks like code, translate it to the other most likely desired language or plain English explanation if vague.

        Code/Request:
        ${code}
        `;
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt
        });
        return response.text?.trim() || "Failed to convert";
    } catch(e) {
        return "Error converting code";
    }
  };

  const handleSubmit = async () => {
    if (!input.trim()) return;
    setLoading(true);
    setOutput('');

    let result = '';
    if (mode === 'regex') {
        result = await generateRegex(input);
    } else if (mode === 'explain') {
        result = await explainCode(input);
    } else {
        result = await convertCode(input);
    }

    setOutput(result);
    setLoading(false);
  };

  const handleCopy = () => {
    if (!output) return;
    navigator.clipboard.writeText(output);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="flex flex-col gap-6 h-full">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="flex items-center gap-2">
            <IconSparkles className="text-yellow-400 w-6 h-6" />
            <h2 className="text-xl font-bold text-slate-100">{t.title}</h2>
        </div>

        <div className="bg-slate-800 p-1 rounded-lg flex border border-slate-700">
            <button
                onClick={() => { setMode('regex'); setOutput(''); setInput(''); }}
                className={`px-3 py-1.5 text-xs sm:text-sm rounded-md transition-all ${mode === 'regex' ? 'bg-primary-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
            >
                {t.regex}
            </button>
            <button
                onClick={() => { setMode('explain'); setOutput(''); setInput(''); }}
                className={`px-3 py-1.5 text-xs sm:text-sm rounded-md transition-all ${mode === 'explain' ? 'bg-primary-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
            >
                {t.explain}
            </button>
             <button
                onClick={() => { setMode('convert'); setOutput(''); setInput(''); }}
                className={`px-3 py-1.5 text-xs sm:text-sm rounded-md transition-all ${mode === 'convert' ? 'bg-primary-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
            >
                {t.convert}
            </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 flex-1">
        {/* Input Column */}
        <div className="flex flex-col gap-2">
            <label className="text-slate-400 text-sm">
                {mode === 'regex' ? t.labelRegex : mode === 'explain' ? t.labelExplain : t.labelConvert}
            </label>
            <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder={mode === 'regex' ? t.phRegex : t.phCode}
                className="flex-1 w-full bg-slate-800 text-slate-200 p-4 rounded-lg border border-slate-700 focus:ring-2 focus:ring-primary-500 outline-none resize-none font-mono text-sm"
            />
            <button
                onClick={handleSubmit}
                disabled={loading || !input.trim()}
                className="w-full py-3 bg-gradient-to-r from-primary-600 to-indigo-600 hover:from-primary-500 hover:to-indigo-500 text-white font-medium rounded-lg shadow transition-all disabled:opacity-50 disabled:cursor-not-allowed flex justify-center items-center gap-2"
            >
                {loading ? (
                    <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                    <>
                        <IconSparkles className="w-4 h-4" />
                        {t.gen}
                    </>
                )}
            </button>
        </div>

        {/* Output Column */}
        <div className="flex flex-col gap-2 relative">
             <div className="flex justify-between items-center">
                <label className="text-slate-400 text-sm">{t.output}</label>
                {output && (
                    <button onClick={handleCopy} className="flex items-center gap-1 text-xs text-primary-500 hover:text-primary-400">
                        {copied ? <IconCheck className="w-3 h-3" /> : <IconCopy className="w-3 h-3" />}
                        {copied ? t.copied : t.copy}
                    </button>
                )}
             </div>
             <div className={`flex-1 w-full bg-slate-900 rounded-lg border border-slate-700 p-4 font-mono text-sm overflow-auto ${!output ? 'flex items-center justify-center text-slate-600 italic' : 'text-green-400'}`}>
                {output || t.resultPlace}
             </div>
        </div>
      </div>
    </div>
  );
};

export default AiAssistant;

import React, { useState, useEffect } from 'react';
import { IconCopy, IconCheck } from '../Icons';
import { ToolComponentProps } from '../../types';

const UrlConverter: React.FC<ToolComponentProps> = ({ lang }) => {
  const [activeTab, setActiveTab] = useState<'convert' | 'parse'>('convert');
  const [input, setInput] = useState('');
  const [output, setOutput] = useState('');
  const [parsedUrl, setParsedUrl] = useState<any>(null);
  const [copied, setCopied] = useState(false);

  const t = {
    title: lang === 'zh' ? 'URL 工具' : 'URL Tools',
    modeConvert: lang === 'zh' ? '编/解码' : 'Encoder/Decoder',
    modeParse: lang === 'zh' ? '解析器' : 'Parser',
    input: lang === 'zh' ? '输入' : 'Input',
    encode: lang === 'zh' ? '编码' : 'Encode',
    decode: lang === 'zh' ? '解码' : 'Decode',
    result: lang === 'zh' ? '结果' : 'Result',
    copy: lang === 'zh' ? '复制' : 'Copy',
    copied: lang === 'zh' ? '已复制' : 'Copied',
    phText: lang === 'zh' ? '输入 URL 或文本...' : 'Enter URL or text...',
    phUrl: lang === 'zh' ? 'https://example.com/path?query=123' : 'https://example.com/path?query=123',
    queryParams: lang === 'zh' ? '查询参数' : 'Query Params',
    resPlace: lang === 'zh' ? '结果将显示在这里...' : 'Result will appear here...',
    invalidUrl: lang === 'zh' ? '请输入有效的 URL 以解析。' : 'Enter a valid URL to parse its components.',
  };

  // Convert Logic
  const handleProcess = (action: 'encode' | 'decode') => {
    if (!input) {
      setOutput('');
      return;
    }
    try {
      if (action === 'encode') {
        setOutput(encodeURIComponent(input));
      } else {
        setOutput(decodeURIComponent(input));
      }
    } catch (e) {
      setOutput('Error: Malformed URL sequence');
    }
  };

  // Parse Logic
  useEffect(() => {
    if (activeTab === 'parse' && input) {
        try {
            const url = new URL(input);
            const params: Record<string, string> = {};
            url.searchParams.forEach((val, key) => { params[key] = val; });

            setParsedUrl({
                Protocol: url.protocol,
                Host: url.hostname,
                Port: url.port,
                Path: url.pathname,
                Query: Object.keys(params).length ? params : null,
                Hash: url.hash
            });
        } catch {
            setParsedUrl(null);
        }
    } else {
        setParsedUrl(null);
    }
  }, [input, activeTab]);

  const handleCopy = (text: string) => {
    if (!text) return;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="flex flex-col gap-6 h-full">
      <div className="flex justify-between items-center">
         <h2 className="text-xl font-bold text-slate-100">{t.title}</h2>
         <div className="bg-slate-800 p-1 rounded-lg flex border border-slate-700">
            <button 
                onClick={() => setActiveTab('convert')}
                className={`px-4 py-1.5 text-sm rounded-md transition-all ${activeTab === 'convert' ? 'bg-primary-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
            >
                {t.modeConvert}
            </button>
            <button 
                onClick={() => setActiveTab('parse')}
                className={`px-4 py-1.5 text-sm rounded-md transition-all ${activeTab === 'parse' ? 'bg-primary-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}
            >
                {t.modeParse}
            </button>
         </div>
      </div>

      {activeTab === 'convert' ? (
        <>
            <div className="flex flex-col gap-2">
                <label className="text-slate-400 text-sm">{t.input}</label>
                <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder={t.phText}
                className="h-32 bg-slate-800 text-slate-200 p-4 rounded-lg border border-slate-700 focus:ring-2 focus:ring-primary-500 outline-none resize-none font-mono text-sm"
                />
            </div>

            <div className="flex gap-4">
                <button
                onClick={() => handleProcess('encode')}
                className="flex-1 py-2 bg-primary-600 hover:bg-primary-500 text-white rounded-lg font-medium transition-colors"
                >
                {t.encode}
                </button>
                <button
                onClick={() => handleProcess('decode')}
                className="flex-1 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-lg font-medium transition-colors"
                >
                {t.decode}
                </button>
            </div>

            <div className="flex flex-col gap-2 flex-1">
                <div className="flex justify-between items-center">
                    <label className="text-slate-400 text-sm">{t.result}</label>
                    {output && (
                        <button onClick={() => handleCopy(output)} className="flex items-center gap-1 text-xs text-primary-500 hover:text-primary-400">
                            {copied ? <IconCheck className="w-3 h-3" /> : <IconCopy className="w-3 h-3" />}
                            {copied ? t.copied : t.copy}
                        </button>
                    )}
                </div>
                <textarea
                readOnly
                value={output}
                placeholder={t.resPlace}
                className="flex-1 h-32 bg-slate-900 text-slate-200 p-4 rounded-lg border border-slate-700 outline-none resize-none font-mono text-sm"
                />
            </div>
        </>
      ) : (
        <div className="flex flex-col gap-4 flex-1">
             <input 
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder={t.phUrl}
                className="w-full bg-slate-800 border border-slate-700 rounded-lg px-4 py-3 text-slate-200 focus:ring-2 focus:ring-primary-500 outline-none font-mono"
             />

             <div className="flex-1 bg-slate-900 rounded-lg border border-slate-800 p-6 overflow-auto">
                 {parsedUrl ? (
                     <div className="space-y-4">
                        {Object.entries(parsedUrl).map(([key, val]) => {
                            if (!val) return null;
                            if (key === 'Query' && typeof val === 'object') {
                                return (
                                    <div key={key}>
                                        <div className="text-xs text-slate-500 uppercase font-bold mb-1">{t.queryParams}</div>
                                        <div className="bg-slate-800 rounded border border-slate-700 p-3 space-y-2">
                                            {Object.entries(val as object).map(([k, v]) => (
                                                <div key={k} className="flex gap-2">
                                                    <span className="text-primary-400 font-mono">{k}:</span>
                                                    <span className="text-green-400 font-mono break-all">{v as string}</span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                );
                            }
                            return (
                                <div key={key} className="flex flex-col gap-1">
                                    <div className="text-xs text-slate-500 uppercase font-bold">{key}</div>
                                    <div className="font-mono text-slate-300 break-all">{val as string}</div>
                                </div>
                            );
                        })}
                     </div>
                 ) : (
                     <div className="text-slate-600 text-center mt-10 italic">
                         {t.invalidUrl}
                     </div>
                 )}
             </div>
        </div>
      )}
    </div>
  );
};

export default UrlConverter;

import React, { useState, useEffect } from 'react';
import { IconClock, IconCopy, IconCheck } from '../Icons';
import { ToolComponentProps } from '../../types';

const TimestampConverter: React.FC<ToolComponentProps> = ({ lang }) => {
  const [now, setNow] = useState(Date.now());
  const [tsInput, setTsInput] = useState('');
  const [dateInput, setDateInput] = useState('');
  const [resultDate, setResultDate] = useState('');
  const [resultTs, setResultTs] = useState('');
  const [copied, setCopied] = useState<string | null>(null);

  const t = {
    current: lang === 'zh' ? '当前时间' : 'Current Time',
    tsToDate: lang === 'zh' ? '时间戳 → 日期' : 'Timestamp → Date',
    dateToTs: lang === 'zh' ? '日期 → 时间戳' : 'Date → Timestamp',
    convert: lang === 'zh' ? '转换' : 'Convert',
    result: lang === 'zh' ? '结果...' : 'Result...',
  };

  useEffect(() => {
    const timer = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(timer);
  }, []);

  const handleTsConvert = () => {
    if (!tsInput) return;
    try {
      let ts = parseInt(tsInput);
      // Guess if seconds (10 digits) or ms (13 digits)
      if (tsInput.length === 10) ts *= 1000;

      const date = new Date(ts);
      if (isNaN(date.getTime())) {
        setResultDate('Invalid Timestamp');
      } else {
        setResultDate(date.toLocaleString() + ' (Local)\n' + date.toUTCString());
      }
    } catch {
      setResultDate('Error');
    }
  };

  const handleDateConvert = () => {
    if (!dateInput) return;
    try {
      const date = new Date(dateInput);
      if (isNaN(date.getTime())) {
        setResultTs('Invalid Date');
      } else {
        const ts = date.getTime();
        setResultTs(`${Math.floor(ts / 1000)} (Seconds)\n${ts} (Milliseconds)`);
      }
    } catch {
      setResultTs('Error');
    }
  };

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopied(id);
    setTimeout(() => setCopied(null), 2000);
  };

  return (
    <div className="flex flex-col gap-8 h-full">
      <div className="flex flex-col md:flex-row justify-between items-center bg-slate-800 p-4 rounded-xl border border-slate-700 shadow-sm">
        <div className="flex items-center gap-3">
          <IconClock className="w-8 h-8 text-primary-500" />
          <div>
            <div className="text-xs text-slate-400 uppercase tracking-wide font-bold">{t.current}</div>
            <div className="text-xl md:text-2xl font-mono text-white font-bold tracking-tight">
              {Math.floor(now / 1000)}
            </div>
          </div>
        </div>
        <div className="text-right mt-2 md:mt-0">
          <div className="text-sm text-slate-300 font-mono">{new Date(now).toLocaleString()}</div>
          <div className="text-xs text-slate-500 font-mono">{new Date(now).toUTCString()}</div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Timestamp to Date */}
        <div className="flex flex-col gap-4">
          <h3 className="text-lg font-semibold text-slate-200 border-b border-slate-700 pb-2">{t.tsToDate}</h3>
          <div className="flex gap-2">
             <input
               type="number"
               value={tsInput}
               onChange={(e) => setTsInput(e.target.value)}
               placeholder="1678900000"
               className="flex-1 bg-slate-800 border border-slate-700 rounded-lg px-4 py-2 text-slate-200 focus:ring-2 focus:ring-primary-500 outline-none font-mono"
             />
             <button onClick={handleTsConvert} className="bg-primary-600 hover:bg-primary-500 text-white px-4 py-2 rounded-lg font-medium transition-colors">
               {t.convert}
             </button>
          </div>
          <div className="bg-slate-900 rounded-lg p-4 border border-slate-800 relative min-h-[80px]">
             {resultDate && (
                 <button 
                   onClick={() => copyToClipboard(resultDate, 'ts-res')} 
                   className="absolute top-2 right-2 text-slate-500 hover:text-primary-400"
                 >
                   {copied === 'ts-res' ? <IconCheck className="w-4 h-4" /> : <IconCopy className="w-4 h-4" />}
                 </button>
             )}
             <pre className="text-green-400 font-mono text-sm whitespace-pre-wrap">{resultDate || t.result}</pre>
          </div>
        </div>

        {/* Date to Timestamp */}
        <div className="flex flex-col gap-4">
          <h3 className="text-lg font-semibold text-slate-200 border-b border-slate-700 pb-2">{t.dateToTs}</h3>
           <div className="flex gap-2">
             <input
               type="text"
               value={dateInput}
               onChange={(e) => setDateInput(e.target.value)}
               placeholder="YYYY-MM-DD HH:mm:ss"
               className="flex-1 bg-slate-800 border border-slate-700 rounded-lg px-4 py-2 text-slate-200 focus:ring-2 focus:ring-primary-500 outline-none font-mono"
             />
             <button onClick={handleDateConvert} className="bg-primary-600 hover:bg-primary-500 text-white px-4 py-2 rounded-lg font-medium transition-colors">
               {t.convert}
             </button>
          </div>
          <div className="bg-slate-900 rounded-lg p-4 border border-slate-800 relative min-h-[80px]">
             {resultTs && (
                 <button 
                   onClick={() => copyToClipboard(resultTs, 'date-res')} 
                   className="absolute top-2 right-2 text-slate-500 hover:text-primary-400"
                 >
                   {copied === 'date-res' ? <IconCheck className="w-4 h-4" /> : <IconCopy className="w-4 h-4" />}
                 </button>
             )}
             <pre className="text-green-400 font-mono text-sm whitespace-pre-wrap">{resultTs || t.result}</pre>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TimestampConverter;

import React, { useState, useEffect } from 'react';
import { IconCheck, IconCopy } from '../Icons';
import { ToolComponentProps } from '../../types';

// Access global Diff object from jsdiff CDN
declare const Diff: any;

const TextDiff: React.FC<ToolComponentProps> = ({ lang }) => {
  const [left, setLeft] = useState('');
  const [right, setRight] = useState('');
  const [diffResult, setDiffResult] = useState<any[]>([]);

  const t = {
    title: lang === 'zh' ? '文本比对' : 'Text Diff / Compare',
    original: lang === 'zh' ? '原始文本' : 'Original Text',
    new: lang === 'zh' ? '新文本' : 'New Text',
    diff: lang === 'zh' ? '差异对比' : 'Difference Comparison',
    placeholderOrig: lang === 'zh' ? '粘贴原始文本...' : 'Paste original text...',
    placeholderNew: lang === 'zh' ? '粘贴新文本...' : 'Paste new text...',
    empty: lang === 'zh' ? '请在两侧输入文本以进行比对。' : 'Enter text in both panels to compare.',
  };

  useEffect(() => {
    if (typeof Diff !== 'undefined') {
        const diff = Diff.diffLines(left, right);
        setDiffResult(diff);
    }
  }, [left, right]);

  return (
    <div className="h-full flex flex-col gap-4">
      <h2 className="text-xl font-bold text-slate-100">{t.title}</h2>

      <div className="flex-1 flex flex-col md:flex-row gap-4 h-[600px] md:h-auto overflow-hidden">
        {/* Input Areas */}
        <div className="flex-1 flex flex-col gap-4 min-h-[300px]">
            <div className="flex-1 flex flex-col">
                <label className="text-sm text-slate-400 mb-2">{t.original}</label>
                <textarea
                    value={left}
                    onChange={(e) => setLeft(e.target.value)}
                    className="flex-1 bg-slate-800 text-slate-200 p-3 rounded-lg border border-slate-700 focus:ring-2 focus:ring-primary-500 outline-none resize-none font-mono text-xs sm:text-sm"
                    placeholder={t.placeholderOrig}
                />
            </div>
            <div className="flex-1 flex flex-col">
                <label className="text-sm text-slate-400 mb-2">{t.new}</label>
                <textarea
                    value={right}
                    onChange={(e) => setRight(e.target.value)}
                    className="flex-1 bg-slate-800 text-slate-200 p-3 rounded-lg border border-slate-700 focus:ring-2 focus:ring-primary-500 outline-none resize-none font-mono text-xs sm:text-sm"
                    placeholder={t.placeholderNew}
                />
            </div>
        </div>

        {/* Diff Output */}
        <div className="flex-1 flex flex-col">
            <label className="text-sm text-slate-400 mb-2">{t.diff}</label>
            <div className="flex-1 bg-slate-900 border border-slate-700 rounded-lg p-4 overflow-auto font-mono text-xs sm:text-sm whitespace-pre-wrap">
                {diffResult.map((part, index) => {
                    let color = 'text-slate-300';
                    let bg = 'bg-transparent';
                    if (part.added) {
                        color = 'text-green-300';
                        bg = 'bg-green-900/30';
                    } else if (part.removed) {
                        color = 'text-red-300';
                        bg = 'bg-red-900/30';
                    }
                    return (
                        <span key={index} className={`${color} ${bg} block w-full px-1`}>
                           {part.value}
                        </span>
                    );
                })}
                {!left && !right && <span className="text-slate-600 italic">{t.empty}</span>}
            </div>
        </div>
      </div>
    </div>
  );
